356	// postRegister POSTs the identity envelope and returns the issued worker_id.
357	func (p *Probe) postRegister(ctx context.Context, addr string) (string, error) {
358		body, err := json.Marshal(p.ident)
359		if err != nil {
360			return "", err
361		}
362		req, err := http.NewRequestWithContext(ctx, http.MethodPost, addr+"/api/workers/register", bytes.NewReader(body))
363		if err != nil {
364			return "", err
365		}
366		req.Header.Set("Content-Type", "application/json")
367		resp, err := p.cfg.HTTPClient.Do(req)
368		if err != nil {
369			return "", err
370		}
371		defer func() { _ = resp.Body.Close() }()
372		if resp.StatusCode != http.StatusOK {
373			return "", fmt.Errorf("register: status=%d", resp.StatusCode)
374		}
375		var out struct {
376			WorkerID string `json:"worker_id"`
377		}
378		if err := json.NewDecoder(resp.Body).Decode(&out); err != nil {
379			return "", err
380		}
381		if out.WorkerID == "" {
382			return "", fmt.Errorf("register: empty worker_id")
383		}
384		return out.WorkerID, nil
385	}
