43	// workerReadyDepthLabel returns a human-readable depth label for the ready count.
44	func workerReadyDepthLabel(count int) string {
45		switch {
46		case count == 0:
47			return "empty"
48		case count <= 1:
49			return "shallow"
50		case count <= 3:
51			return "moderate"
52		default:
53			return "deep"
54		}
55	}
