1248	// workerDirPID reads the PID from .ddx/workers/<id>/status.json. Returns 0
1249	// if the file cannot be read or has no PID.
1250	func workerDirPID(dirPath string) int {
1251		data, err := os.ReadFile(filepath.Join(dirPath, "status.json"))
1252		if err != nil {
1253			return 0
1254		}
1255		var rec struct {
1256			PID int `json:"pid"`
1257		}
1258		if err := json.Unmarshal(data, &rec); err != nil {
1259			return 0
1260		}
1261		return rec.PID
1262	}
