1264	// pruneWorkerDirs deletes .ddx/workers/<id>/ directories whose mtime is older
1265	// than m.RetainDays. Directories whose status.json PID is still alive are
1266	// skipped. No-op when RetainDays == 0.
1267	func (m *ExecutionCleanupManager) pruneWorkerDirs(_ context.Context, summary *ExecutionCleanupSummary, now time.Time) {
1268		if m.RetainDays == 0 {
1269			return
1270		}
1271		cutoff := now.AddDate(0, 0, -m.RetainDays)
1272	
1273		root := filepath.Join(m.ProjectRoot, ".ddx", "workers")
1274		entries, err := os.ReadDir(root)
1275		if err != nil {
1276			if !errors.Is(err, os.ErrNotExist) {
1277				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
1278					Path:    root,
1279					Class:   "worker_dir_read",
1280					Message: err.Error(),
1281				})
1282			}
1283			return
1284		}
1285	
1286		for _, entry := range entries {
1287			if !entry.IsDir() {
1288				continue
1289			}
1290			dirPath := filepath.Join(root, entry.Name())
1291			relPath := filepath.ToSlash(filepath.Join(".ddx/workers", entry.Name()))
1292	
1293			if pid := workerDirPID(dirPath); pid > 0 && trackerProcessAlive(pid) {
1294				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
1295					Path:    relPath,
1296					Class:   "preserved_active_worker_dir",
1297					Message: fmt.Sprintf("worker pid %d is alive", pid),
1298				})
1299				continue
1300			}
1301	
1302			info, infoErr := entry.Info()
1303			if infoErr != nil {
1304				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
1305					Path:    dirPath,
1306					Class:   "worker_dir_stat",
1307					Message: infoErr.Error(),
1308				})
1309				continue
1310			}
1311			if !info.ModTime().Before(cutoff) {
1312				continue
1313			}
1314	
1315			if !m.DryRun {
1316				if err := os.RemoveAll(dirPath); err != nil {
1317					summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
1318						Path:    dirPath,
1319						Class:   "worker_dir_remove",
1320						Message: err.Error(),
1321					})
1322					continue
1323				}
1324			}
1325			summary.RemovedWorkerDirs++
1326			class := "removed_worker_dir"
1327			if m.DryRun {
1328				class = "would_remove_worker_dir"
1329			}
1330			summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
1331				Path:    relPath,
1332				Class:   class,
1333				Message: fmt.Sprintf("worker dir older than %d days", m.RetainDays),
1334			})
1335		}
