108	// FilterByProject returns workers whose ProjectRoot resolves to the same path
109	// as projectRoot. Resolution canonicalises both sides via filepath.Abs and
110	// filepath.EvalSymlinks so a symlinked checkout matches its real path.
111	func FilterByProject(workers []LiveWorker, projectRoot string) []LiveWorker {
112		target := canonicalPath(projectRoot)
113		out := make([]LiveWorker, 0, len(workers))
114		for _, w := range workers {
115			if SamePath(w.ProjectRoot, target) {
116				out = append(out, w)
117			}
118		}
119		return out
120	}
121	
122	// SamePath reports whether a and b refer to the same on-disk location after
123	// canonicalisation. It tolerates empty inputs (returning false) so callers
124	// can safely compare optional fields without prefiltering.
125	func SamePath(a, b string) bool {
126		ca := canonicalPath(a)
127		cb := canonicalPath(b)
128		if ca == "" || cb == "" {
129			return false
130		}
131		return ca == cb
132	}
133	
134	func canonicalPath(p string) string {
135		if strings.TrimSpace(p) == "" {
136			return ""
137		}
138		abs, err := filepath.Abs(p)
139		if err != nil {
140			abs = filepath.Clean(p)
141		}
142		if resolved, err := filepath.EvalSymlinks(abs); err == nil {
143			return resolved
144		}
145		return abs
146	}
